// ===== RAPOARTE =====
function renderRapoarte() {
    const cats = {};
    DB.inventar.forEach(b => {
        cats[b.cat] = (cats[b.cat] || 0) + b.qty;
    }
    );
    const colors = ['#d4a843', '#0d7c6b', '#1a6fa8', '#c0392b', '#7c3aed', '#d97706'];
    const maxC = Math.max(...Object.values(cats), 1);
    document.getElementById('repCat').innerHTML = Object.entries(cats).map( ([k,v], i) => `<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>${k}</span><span>${v} buc.</span></div><div style="background:var(--surface);border-radius:4px;height:8px"><div style="width:${Math.round(v / maxC * 100)}%;height:100%;border-radius:4px;background:${colors[i % colors.length]};transition:width 0.8s"></div></div></div>`).join('') || '<p style="color:var(--mist);font-size:13px">Nicio dată</p>';

    const cldV = {};
    DB.inventar.forEach(b => {
        cldV[b.cladireId] = (cldV[b.cladireId] || 0) + b.val;
    }
    );
    const maxV = Math.max(...Object.values(cldV), 1);
    document.getElementById('repCladiri').innerHTML = Object.entries(cldV).map( ([cid,v], i) => {
        const c = DB.cladiri.find(x => x.id == cid);
        return `<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>${c ? c.cod : '—'}</span><span>${v.toLocaleString('ro-RO')} RON</span></div><div style="background:var(--surface);border-radius:4px;height:8px"><div style="width:${Math.round(v / maxV * 100)}%;height:100%;border-radius:4px;background:${colors[i % colors.length]}"></div></div></div>`
    }
    ).join('') || '<p style="color:var(--mist);font-size:13px">Nicio dată</p>';

    const achByM = {};
    DB.achizitii.forEach(a => {
        const m = (a.data || '').substring(0, 7);
        achByM[m] = (achByM[m] || 0) + a.val;
    }
    );
    document.getElementById('repAch').innerHTML = Object.entries(achByM).sort().map( ([m,v]) => `<div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>${m}</span><span>${v.toLocaleString('ro-RO')} RON</span></div><div style="background:var(--surface);border-radius:4px;height:8px"><div style="width:${Math.round(v / Math.max(...Object.values(achByM)) * 100)}%;height:100%;border-radius:4px;background:#1a6fa8"></div></div></div>`).join('') || '<p style="color:var(--mist);font-size:13px">Nicio achiziție</p>';

    const open = DB.tasks.filter(t => ['deschis', 'Deschisă', 'deschisa'].includes(t.status)).length;
    const done = DB.tasks.filter(t => t.status === 'finalizat').length;
    const tot = open + done || 1;
    document.getElementById('repTask').innerHTML = `
    <div style="margin-bottom:10px"><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>Deschise</span><span>${open}</span></div><div style="background:var(--surface);border-radius:4px;height:8px"><div style="width:${Math.round(open / tot * 100)}%;height:100%;border-radius:4px;background:#c0392b"></div></div></div>
    <div><div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>Finalizate</span><span>${done}</span></div><div style="background:var(--surface);border-radius:4px;height:8px"><div style="width:${Math.round(done / tot * 100)}%;height:100%;border-radius:4px;background:#0d7c6b"></div></div></div>`;
}

// ===== DASHBOARD =====
function updateDashboard() {
    const isSuper = currentUser?.rol === 'super_admin';

    if (isSuper) {
        const sCladiri = document.getElementById('s-cladiri');
        if (sCladiri) {
            sCladiri.textContent = (DB.schools || []).length;
            if (sCladiri.previousElementSibling)
                sCladiri.previousElementSibling.textContent = "Tenanți (Școli)";
            if (sCladiri.nextElementSibling)
                sCladiri.nextElementSibling.textContent = "în platformă";
        }
        const sBunuri = document.getElementById('s-bunuri');
        if (sBunuri) {
            sBunuri.textContent = (DB.personal || []).length;
            if (sBunuri.previousElementSibling)
                sBunuri.previousElementSibling.textContent = "Utilizatori Sistem";
            if (sBunuri.nextElementSibling)
                sBunuri.nextElementSibling.innerHTML = `<span title="Include toți utilizatorii înregistrați">conturi înregistrate</span>`;
        }
        const sRep = document.getElementById('s-rep');
        if (sRep) {
            sRep.textContent = (DB.schools || []).filter(t => t.active).length;
            if (sRep.previousElementSibling)
                sRep.previousElementSibling.textContent = "Clienți Activi";
            if (sRep.nextElementSibling)
                sRep.nextElementSibling.textContent = "cu licență validă";
        }
        const sVal = document.getElementById('s-val');
        if (sVal) {
            sVal.textContent = (DB.schools || []).filter(t => !t.active).length;
            if (sVal.previousElementSibling)
                sVal.previousElementSibling.textContent = "Clienți Inactivi";
            if (sVal.nextElementSibling)
                sVal.nextElementSibling.textContent = "suspendați / expirați";
        }
        const sTasks = document.getElementById('s-tasks');
        if (sTasks) {
            sTasks.textContent = "OK";
            if (sTasks.previousElementSibling)
                sTasks.previousElementSibling.textContent = "Stare Sistem";
            if (sTasks.nextElementSibling)
                sTasks.nextElementSibling.textContent = "operațional";
        }

        // Ascunde chart-urile dacă există wrapper
        if (document.getElementById('chartStare'))
            document.getElementById('chartStare').parentElement.parentElement.style.display = 'none';
        if (document.getElementById('chartCladiri'))
            document.getElementById('chartCladiri').parentElement.parentElement.style.display = 'none';
        const dashTasksEl = document.getElementById('dashTasks');
        if (dashTasksEl && dashTasksEl.parentElement)
            dashTasksEl.parentElement.style.display = 'none';

        // Redesenează Card-ul de Clădiri cu Tenanți
        const dashCladiriEl = document.getElementById('dashCladiri');
        if (dashCladiriEl) {
            if (dashCladiriEl.parentElement) {
                const cardTitle = dashCladiriEl.parentElement.querySelector('.card-title');
                if (cardTitle)
                    cardTitle.innerHTML = `🌐 Management Tenanți (Instanțe Client)`;
                dashCladiriEl.parentElement.style.gridColumn = "1 / -1";
            }

            let tenantRows = (DB.schools || []).slice().sort( (a, b) => a.id - b.id).map(t => {
                const statusClass = t.active ? 'b-teal' : 'b-gray';
                const licLabel = t.licenta || 'STANDARD';
                const statusLabel = t.active ? (licLabel === 'FREE' ? 'Trial' : 'Activ') : 'Inactiv';
                const btnLabel = t.active ? '&#128273; Acces Instanță' : '&#128274; Activați';

                return `<tr>
              <td><strong>${t.nume}</strong><br><small style="color:var(--mist)">${licLabel}</small></td>
              <td>${t.id} (${t.cod})</td>
              <td>${t.admin}</td>
              <td><span class="badge ${statusClass}" onclick="toggleTenantStatus(${t.id})" style="cursor:pointer" title="Click pentru schimbare status">${statusLabel}</span></td>
              <td style="display:flex;gap:6px;flex-wrap:wrap">
                <button class="btn btn-sm btn-outline" onclick="editTenant(${t.id})">&#9998; Editează</button>
                <button class="btn btn-sm btn-enter-tenant" style="background:${t.active ? 'var(--gold)' : 'var(--mist)'};color:#fff" 
                        data-tenant-id="${t.id}" data-tenant-cod="${t.cod}" data-active="${t.active}">
                  ${btnLabel}
                </button>
                <button class="btn btn-sm btn-outline" onclick="exportTenantData(${t.id})" title="Export Date">📤</button>
                <button class="btn btn-sm btn-danger" onclick="deleteTenant(${t.id})" title="Ștergere Cont">🗑️</button>
              </td>
            </tr>`;
            }
            ).join('');

            dashCladiriEl.innerHTML = `
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;padding:0 4px">
              <span style="font-size:12px;color:var(--mist)">Instanțe gestionate de platformă</span>
              <button class="btn btn-sm btn-primary" onclick="addNewTenant()" style="gap:4px">+ Adaugă Client Nou</button>
            </div>
            <div class="table-container">
              <table class="table">
                <tr><th>Client (Școală)</th><th>Cod</th><th>Administrator</th><th>Statut</th><th>Acțiuni</th></tr>
                ${tenantRows}
              </table>
            </div>
            <p style="margin-top:15px; font-size:11px; color:var(--mist)">*Notă: "Acces Instanță" te autentifică ca administrator pe platforma școlii. "Editează" deschide profilul clientului.</p>
          `;

            document.querySelectorAll(".btn-enter-tenant").forEach(btn => {
                btn.addEventListener("click", () => {
                    const tenantId = parseInt(btn.dataset.tenantId);
                    const tenantCod = btn.dataset.tenantCod;
                    const isActive = btn.dataset.active === 'true';
                    if (isActive) {
                        switchToTenant(tenantId, tenantCod);
                    } else {
                        activateTenant(tenantId);
                    }
                }
                );
            }
            );
        }
    } else {
        // School Admin / User mode -> Dashboard v2.0
        updateDashboardV2();
    }
}

/** Dashboard v2.0 logic */
function updateDashboardV2() {
    // 1. KPI Calculation
    const totBun = (DB.inventar || []).reduce( (s, b) => s + (parseInt(b.qty) || 1), 0);
    const nCladiri = (DB.cladiri || []).length;
    const valTotala = (DB.inventar || []).reduce( (s, b) => s + (parseFloat(b.val) || 0), 0);
    const openTasks = (DB.tasks || []).filter(t => ['deschis', 'Deschisă', 'deschisa'].includes(t.status)).length;

    const kpiBunuri = document.getElementById('s-bunuri');
    const kpiCladiri = document.getElementById('s-cladiri');
    const kpiVal = document.getElementById('s-val');
    const kpiTasks = document.getElementById('s-tasks');

    if (kpiBunuri)
        kpiBunuri.textContent = totBun;
    if (kpiCladiri)
        kpiCladiri.textContent = nCladiri;
    if (kpiVal)
        kpiVal.textContent = valTotala.toLocaleString('ro-RO');
    if (kpiTasks)
        kpiTasks.textContent = openTasks;

    // 2. Render Lists & Tables
    renderDashMentenanta();
    renderDashActivity();
    renderDashRecentInv();

    // 3. Render Charts
    renderDashboardV2Charts();
}

/** Dashboard v2.0: Alerte Mentenanta */
function renderDashMentenanta() {
    const table = document.getElementById('dashMentenantaTable');
    if (!table)
        return;

    const alerte = (DB.tasks || []).filter(t => t.status !== 'finalizat').sort( (a, b) => {
        const prioMap = {
            'Înaltă': 1,
            'Medie': 2,
            'Scăzută': 3
        };
        return (prioMap[a.prioritate] || 99) - (prioMap[b.prioritate] || 99);
    }
    ).slice(0, 6);

    if (alerte.length === 0) {
        table.innerHTML = '<tr><td colspan="3" style="text-align:center; padding:20px; color:var(--mist)">Nicio alertă activă</td></tr>';
        return;
    }

    table.innerHTML = alerte.map(t => {
        const prioColor = t.prioritate === 'Înaltă' ? 'var(--rose)' : (t.prioritate === 'Medie' ? 'var(--gold)' : 'var(--teal)');
        return `<tr>
      <td><strong>${t.titlu || '—'}</strong></td>
      <td><span class="badge" style="background:${prioColor}; color:white">${t.prioritate || 'Medie'}</span></td>
      <td style="font-size:11px; color:var(--mist)">${t.termen || '—'}</td>
    </tr>`;
    }
    ).join('');
}

/** Dashboard v2.0: Activitate Recenta */
function renderDashActivity() {
    const container = document.getElementById('dashActivityList');
    if (!container)
        return;

    const logs = (activities || []).slice().reverse().slice(0, 8);

    if (logs.length === 0) {
        container.innerHTML = '<div style="text-align:center; padding:20px; color:var(--mist)">Nicio activitate recentă</div>';
        return;
    }

    container.innerHTML = `<ul style="list-style: none; padding: 0; margin: 0; display: flex; flex-direction: column; gap: 12px;">
    ${logs.map(a => `
      <li style="display: flex; justify-content: space-between; align-items: flex-start; gap: 8px; font-size: 13px; border-bottom:1px solid var(--surface); padding-bottom:8px">
        <span style="color: var(--ink); line-height: 1.4;">${a.msg}</span>
        <span style="color: var(--mist); font-size: 11px; white-space: nowrap;">${a.time}</span>
      </li>
    `).join('')}
  </ul>`;
}

/** Dashboard v2.0: Recent Inventory table */
function renderDashRecentInv() {
    const table = document.getElementById('dashRecentInvTable');
    if (!table)
        return;

    const recent = (DB.inventar || []).slice().reverse().slice(0, 20);

    if (recent.length === 0) {
        table.innerHTML = '<tr><td colspan="5" style="text-align:center; padding:20px; color:var(--mist)">Inventar gol</td></tr>';
        return;
    }

    table.innerHTML = recent.map(b => `
    <tr>
      <td><strong>${b.nrInv}</strong></td>
      <td>${b.nume}</td>
      <td><span style="font-size:11px; color:var(--mist)">${b.cat}</span></td>
      <td><strong>${(parseFloat(b.val) || 0).toLocaleString('ro-RO')}</strong> <small>RON</small></td>
      <td><span class="badge ${b.stare === 'BUN' ? 'b-teal' : (b.stare === 'UZAT' ? 'b-gold' : 'b-gray')}">${b.stare}</span></td>
    </tr>
  `).join('');
}

/** Dashboard v2.0 Charts Implementation */
let chartCladiriValObj = null;
let chartCategoriiValObj = null;

function renderDashboardV2Charts() {
    const isDash = document.getElementById('section-dashboard').classList.contains('active');
    if (!isDash)
        return;

    // Chart 1: Valoare pe cladiri
    const ctxCladiri = document.getElementById('chartCladiriValoare');
    if (ctxCladiri && typeof Chart !== 'undefined') {
        const labels = (DB.cladiri || []).map(c => c.cod);
        const data = (DB.cladiri || []).map(c => {
            return (DB.inventar || []).filter(b => b.cladireId === c.id).reduce( (s, b) => s + (parseFloat(b.val) || 0), 0);
        }
        );

        if (chartCladiriValObj)
            chartCladiriValObj.destroy();
        chartCladiriValObj = new Chart(ctxCladiri,{
            type: 'bar',
            data: {
                labels: labels,
                datasets: [{
                    label: 'Valoare (RON)',
                    data: data,
                    backgroundColor: '#3b82f6',
                    borderRadius: 4
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        display: false
                    }
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        ticks: {
                            font: {
                                size: 10
                            }
                        }
                    },
                    x: {
                        ticks: {
                            font: {
                                size: 10
                            }
                        }
                    }
                }
            }
        });
    }

    // Chart 2: Structura pe categorii
    const ctxCat = document.getElementById('chartCategoriiValoare');
    if (ctxCat && typeof Chart !== 'undefined') {
        const map = {};
        (DB.inventar || []).forEach(b => {
            const c = b.cat || 'Altele';
            map[c] = (map[c] || 0) + (parseFloat(b.val) || 0);
        }
        );

        const labels = Object.keys(map);
        const data = Object.values(map);
        const colors = ['#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

        if (chartCategoriiValObj)
            chartCategoriiValObj.destroy();
        chartCategoriiValObj = new Chart(ctxCat,{
            type: 'doughnut',
            data: {
                labels: labels,
                datasets: [{
                    data: data,
                    backgroundColor: colors.slice(0, labels.length),
                    borderWidth: 0
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                cutout: '65%',
                plugins: {
                    legend: {
                        position: 'right',
                        labels: {
                            boxWidth: 10,
                            font: {
                                size: 10
                            }
                        }
                    }
                }
            }
        });
    }
}

