// ===== PERSISTENT ISTORIC (localStorage) =====
function persistIstoric() {
    try {
        localStorage.setItem('patrimonet_istoric', JSON.stringify(istoricLog));
        localStorage.setItem('patrimonet_activities', JSON.stringify(activities));
    } catch (e) {
        console.warn('[PERSIST] Nu am putut salva istoricul:', e);
    }
}

function loadPersistedIstoric() {
    try {
        var saved = localStorage.getItem('patrimonet_istoric');
        var savedAct = localStorage.getItem('patrimonet_activities');
        if (saved) {
            var parsed = JSON.parse(saved);
            if (Array.isArray(parsed) && parsed.length > 0) {
                istoricLog = parsed;
            }
        }
        if (savedAct) {
            var parsedAct = JSON.parse(savedAct);
            if (Array.isArray(parsedAct) && parsedAct.length > 0) {
                activities = parsedAct;
            }
        }
    } catch (e) {
        console.warn('[PERSIST] Nu am putut incarca istoricul:', e);
    }
}

let chartStareObj = null;
let chartCladiriObj = null;

function renderDashboardCharts(functional, reparatii, casat) {
    const ctxStare = document.getElementById('chartStare');
    if (ctxStare) {
        if (chartStareObj)
            chartStareObj.destroy();
        chartStareObj = new Chart(ctxStare,{
            type: 'doughnut',
            data: {
                labels: ['BUN', 'UZAT', 'CASAT'],
                datasets: [{
                    data: [functional, reparatii, casat],
                    backgroundColor: ['#0d7c6b', '#d97706', '#c0392b'],
                    borderWidth: 0,
                    hoverOffset: 4
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        position: 'bottom',
                        labels: {
                            boxWidth: 12,
                            font: {
                                size: 11
                            }
                        }
                    }
                },
                cutout: '70%'
            }
        });
    }

    const ctxCladiri = document.getElementById('chartCladiri');
    if (ctxCladiri) {
        const sortedCladiri = (DB.cladiri || []).slice().sort( (a, b) => a.cod.localeCompare(b.cod, 'ro'));
        const labels = sortedCladiri.map(c => c.cod);
        const data = sortedCladiri.map(c => DB.inventar.filter(b => b.cladireId === c.id).length);
        if (chartCladiriObj)
            chartCladiriObj.destroy();
        chartCladiriObj = new Chart(ctxCladiri,{
            type: 'bar',
            data: {
                labels: labels,
                datasets: [{
                    label: 'Număr bunuri',
                    data: data,
                    backgroundColor: '#d4a843',
                    borderRadius: 6,
                    barThickness: 30
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    y: {
                        beginAtZero: true,
                        grid: {
                            color: 'rgba(0,0,0,0.05)'
                        },
                        ticks: {
                            font: {
                                size: 11,
                                family: 'Sora'
                            },
                            stepSize: 1
                        }
                    },
                    x: {
                        grid: {
                            display: false
                        },
                        ticks: {
                            font: {
                                size: 11,
                                family: 'Sora'
                            }
                        }
                    }
                },
                plugins: {
                    legend: {
                        display: false
                    },
                    tooltip: {
                        backgroundColor: 'rgba(26, 31, 46, 0.9)',
                        titleFont: {
                            family: 'Sora',
                            size: 13
                        },
                        bodyFont: {
                            family: 'Sora',
                            size: 12
                        },
                        padding: 10,
                        cornerRadius: 8
                    }
                }
            }
        });
    }
}

function updateBadges() {
    // Open tasks - check all status variants
    const open = DB.tasks.filter(t => ['deschis', 'Deschisă', 'deschisa'].includes(t.status)).length;
    const tb = document.getElementById('taskBadge');
    if (tb) {
        tb.textContent = open;
        tb.style.display = open ? 'inline' : 'none';
    }
    // Notification dot
    const notifDot = document.getElementById('notifDot');
    if (notifDot)
        notifDot.style.display = (notifications || []).filter(n => !n.read).length ? 'block' : 'none';
    // Achizitii pending approval
    const achPending = DB.achizitii.filter(a => a.status === 'Comandat').length;
    const ab = document.getElementById('achBadge');
    if (ab) {
        ab.textContent = achPending;
        ab.style.display = achPending ? 'inline' : 'none';
    }
    // Aprobari count
    const aprobPending = (DB.aprobari || []).filter(a => a.status === 'pending').length + DB.mutari.filter(m => m.status === 'În așteptare aprobare').length + DB.rezervari.filter(r => r.status === 'În așteptare aprobare').length;
    const aprobBadge = document.getElementById('aprobBadge');
    if (aprobBadge) {
        aprobBadge.textContent = aprobPending;
        aprobBadge.style.display = aprobPending ? 'inline' : 'none';
    }
}

// ===== SETTINGS =====
function loadLogo(input) {
    if (!input.files || !input.files[0])
        return;
    const r = new FileReader();
    r.onload = e => {
        const img = document.getElementById('logoPreview');
        img.src = e.target.result;
        img.style.display = 'block';
        document.getElementById('logoPlaceholder').style.display = 'none';
        document.getElementById('sidebarLogoBox').innerHTML = `<img src="${e.target.result}" style="width:100%;height:100%;object-fit:contain;border-radius:6px">`;
        toast('✅ Logo încărcat!');
    }
    ;
    r.readAsDataURL(input.files[0]);
}
function removeLogo() {
    document.getElementById('logoPreview').style.display = 'none';
    document.getElementById('logoPreview').src = '';
    document.getElementById('logoPlaceholder').style.display = 'block';
    document.getElementById('sidebarLogoBox').textContent = '🏫';
    toast('Logo eliminat!');
}
function saveSettings() {
    const name = document.getElementById('setNume').value;
    document.getElementById('sidebarSchoolName').textContent = name.substring(0, 40);
    toast('✅ Date instituție salvate!');
    addActivity('Date instituție actualizate', 'gold');
}

