// ===== MUTARI BUNURI =====
DB.mutari = DB.mutari || [];

function renderMutari(data) {
    const items = data || DB.mutari;
    document.getElementById('mutariCount').textContent = items.length + ' mutări';
    const t = document.getElementById('mutariTable');
    if (!items.length) {
        t.innerHTML = '<tr><td colspan="8"><div class="empty"><div class="empty-icon">🔀</div><p>Nicio mutare înregistrată.</p></div></td></tr>';
        return;
    }
    const sb = {
        Finalizată: 'b-green',
        'În așteptare aprobare': 'b-yellow',
        Respinsă: 'b-red'
    };
    t.innerHTML = items.map(m => {
        const b = DB.inventar.find(x => x.id == m.bunId);
        const user = DB.personal.find(x => x.id == m.userId);
        return `<tr>
      <td style="font-size:11px">${m.data}</td>
      <td><strong>${b ? b.nrInv : '—'}</strong><div style="font-size:11px;color:var(--mist)">${b ? b.nume.substring(0, 30) : '—'}</div></td>
      <td style="font-size:11px">${m.deCladire} / ${m.deCamera}</td>
      <td style="font-size:11px">${m.laCladire} / ${m.laCamera}</td>
      <td style="font-size:11px">${m.motiv}</td>
      <td style="font-size:11px">${user ? user.prenume + ' ' + user.nume : '—'}</td>
      <td><span class="badge ${sb[m.status] || 'b-gray'}">${m.status}</span></td>
      <td>
        ${m.status === 'În așteptare aprobare' && ['director', 'school_admin'].includes(currentUser?.rol) ? `<button class="btn btn-teal btn-sm" onclick="aprobaMutare(${m.id},true)">✓</button>
           <button class="btn btn-danger btn-sm" onclick="aprobaMutare(${m.id},false)">✗</button>` : ''}
      </td>
    </tr>`;
    }
    ).join('');
}

function filterMutari(q) {
    const s = (q || '').toLowerCase();
    const status = document.getElementById('filterMutareStatus').value;
    renderMutari(DB.mutari.filter(m => (!s || m.motiv.toLowerCase().includes(s) || m.deCamera.toLowerCase().includes(s) || m.laCamera.toLowerCase().includes(s)) && (!status || m.status === status)));
}

function openModalMutare() {
    document.getElementById('mutareEditId').value = '';
    const bunOpts = DB.inventar.map(b => `<option value="${b.id}">${b.nrInv} — ${b.nume.substring(0, 40)}</option>`).join('');
    document.getElementById('mutareBun').innerHTML = '<option value="">— Selectează bunul —</option>' + bunOpts;
    document.getElementById('mutareDeCladire').value = '';
    document.getElementById('mutareDeCamera').value = '';
    populateCladireSelects();
    document.getElementById('mutareLaCladire').innerHTML = DB.cladiri.map(c => `<option value="${c.id}">${c.cod} — ${c.nume.substring(0, 30)}</option>`).join('');
    updateMutareCamere();
    openModal('modalMutare');
}

function updateMutareBunInfo() {
    const id = parseInt(document.getElementById('mutareBun').value);
    const b = DB.inventar.find(x => x.id === id);
    const info = document.getElementById('mutareBunInfo');
    if (!b) {
        info.style.display = 'none';
        return;
    }
    const cld = DB.cladiri.find(x => x.id === b.cladireId);
    const cam = DB.camere.find(x => x.id === b.cameraId);
    document.getElementById('mutareDeCladire').value = cld ? cld.cod + ' — ' + cld.nume.substring(0, 25) : 'Neatribuit';
    document.getElementById('mutareDeCamera').value = cam ? cam.cod + ' — ' + cam.nume : 'Neatribuită';
    info.style.display = 'block';
    info.innerHTML = `<strong>${b.nrInv}</strong> · ${b.cat} · Stare: <strong>${b.stare}</strong> · Valoare: <strong>${b.val.toLocaleString('ro-RO')} RON</strong>`;
}

function updateMutareCamere() {
    const cldId = parseInt(document.getElementById('mutareLaCladire').value);
    document.getElementById('mutareLaCamera').innerHTML = DB.camere.filter(c => !cldId || c.cladireId === cldId).map(c => `<option value="${c.id}">${c.cod} — ${c.nume}</option>`).join('');
}

function saveMutare() {
    if (window._isSaving)
        return;
    window._isSaving = true;
    setTimeout( () => window._isSaving = false, 1000);
    const bunId = parseInt(document.getElementById('mutareBun').value);
    if (!bunId) {
        toast('⚠️ Selectează bunul!');
        return;
    }
    const b = DB.inventar.find(x => x.id === bunId);
    const laCamId = parseInt(document.getElementById('mutareLaCamera').value);
    const laCld = DB.cladiri.find(x => x.id === parseInt(document.getElementById('mutareLaCladire').value));
    const laCam = DB.camere.find(x => x.id === laCamId);
    const aprob = document.getElementById('mutareAprobare').value;
    const deCld = DB.cladiri.find(x => x.id === b.cladireId);
    const deCam = DB.camere.find(x => x.id === b.cameraId);

    const m = {
        id: Date.now(),
        bunId,
        userId: currentUser.id,
        data: new Date().toLocaleDateString('ro-RO'),
        deCladire: deCld ? deCld.cod : 'Neatribuit',
        deCamera: deCam ? deCam.cod : 'Neatribuită',
        laCladire: laCld ? laCld.cod : '—',
        laCamera: laCam ? laCam.cod : '—',
        laCladireId: laCld ? laCld.id : null,
        laCameraId: laCamId || null,
        motiv: document.getElementById('mutareMotiv').value,
        obs: document.getElementById('mutareObs').value,
        status: aprob === 'da' ? 'În așteptare aprobare' : 'Finalizată'
    };

    DB.mutari.unshift(m);
    sbAutoSave('mutari', m);

    if (aprob !== 'da') {
        // Apply move immediately
        b.cladireId = m.laCladireId || b.cladireId;
        b.cameraId = m.laCameraId || b.cameraId;
        sbAutoSave('inventar', b);
        toast('✅ Mutare înregistrată și aplicată!');
        addNotification('Mutare bun finalizată', `${b.nrInv} — ${b.nume.substring(0, 30)} → ${m.laCamera}`, 'mutare', ['school_admin', 'super_admin']);
    } else {
        toast('⏳ Mutare trimisă spre aprobare director!');
        addNotification('Cerere mutare bun', `${b.nrInv} necesită aprobare pentru mutare în ${m.laCamera}`, 'aprobare', ['director', 'school_admin']);
        updateAprobari();
    }

    addIstoricEvent('mutari', `Mutare bun: ${b.nrInv} din ${m.deCamera} → ${m.laCamera}`, currentUser);
    closeModal('modalMutare');
    renderMutari();
    updateDashboard();
}

function aprobaMutare(id, approved) {
    const m = DB.mutari.find(x => x.id === id);
    if (!m)
        return;
    m.status = approved ? 'Finalizată' : 'Respinsă';
    m.aprobatDe = currentUser.prenume + ' ' + currentUser.nume;
    m.aprobatLa = new Date().toLocaleDateString('ro-RO');
    if (approved) {
        const b = DB.inventar.find(x => x.id === m.bunId);
        if (b) {
            b.cladireId = m.laCladireId || b.cladireId;
            b.cameraId = m.laCameraId || b.cameraId;
        }
        toast('✅ Mutare aprobată și aplicată!');
        addNotification('Mutare aprobată', `Mutarea a fost aprobată de ${currentUser.prenume} ${currentUser.nume}`, 'aprobare', ['school_admin']);
    } else {
        toast('❌ Mutare respinsă!');
        addNotification('Mutare respinsă', `Mutarea a fost respinsă de ${currentUser.prenume} ${currentUser.nume}`, 'aprobare', ['school_admin']);
    }
    addIstoricEvent('aprobare', `Mutare ${approved ? 'aprobată' : 'respinsă'} de ${currentUser.prenume} ${currentUser.nume}`, currentUser);
    renderMutari();
    updateAprobari();
}

// ===== REZERVARI SALI =====
DB.rezervari = DB.rezervari || [];

function renderCalendarRez() {
    const camId = document.getElementById('filterRezCam').value;
    const data = document.getElementById('filterRezData').value || new Date().toISOString().split('T')[0];
    const grid = document.getElementById('calendarRezGrid');
    const camere = camId ? DB.camere.filter(c => c.id == camId) : DB.camere;
    const ore = ['00:00', '01:00', '02:00', '03:00', '04:00', '05:00', '06:00', '07:00', '08:00', '09:00', '10:00', '11:00', '12:00', '13:00', '14:00', '15:00', '16:00', '17:00', '18:00', '19:00', '20:00', '21:00', '22:00', '23:00'];

    grid.innerHTML = `<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;min-width:600px">
    <thead><tr><th style="padding:8px;background:var(--surface);border:1px solid var(--border);text-align:left;font-size:11px;min-width:120px">Sală / Oră</th>
    ${ore.map(o => `<th style="padding:6px 4px;background:var(--surface);border:1px solid var(--border);font-size:10px;text-align:center;white-space:nowrap">${o}</th>`).join('')}</tr></thead>
    <tbody>
    ${camere.map(cam => {
        const cld = DB.cladiri.find(x => x.id === cam.cladireId);
        return `<tr>
        <td style="padding:6px 10px;border:1px solid var(--border);font-size:11px;font-weight:600;background:var(--surface)">${cam.cod}<div style="font-weight:400;color:var(--mist)">${cld ? cld.cod : ''}</div></td>
        ${ore.map(ora => {
            const rez = DB.rezervari.find(r => r.cameraId == cam.id && r.data === data && r.oraStart === ora);
            if (rez) {
                const cls = rez.status === 'Aprobată' ? 'rz-confirmed' : rez.status === 'Respinsă' ? 'rz-rejected' : 'rz-pending';
                return `<td style="padding:3px;border:1px solid var(--border)"><div class="${cls}" style="font-size:9px;padding:3px 5px;cursor:pointer" onclick="viewRezervare(${rez.id})" title="${rez.materie}">${rez.materie.substring(0, 12)}</div></td>`;
            }
            return `<td style="padding:3px;border:1px solid var(--border);text-align:center"><span style="font-size:10px;color:var(--border);cursor:pointer" onclick="quickRezervare(${cam.id},'${ora}','${data}')" title="Rezervă">+</span></td>`;
        }
        ).join('')}
      </tr>`;
    }
    ).join('')}
    </tbody></table></div>
    <div style="display:flex;gap:14px;margin-top:10px;font-size:11px">
      <span><span style="display:inline-block;width:12px;height:12px;background:#d1fae5;border-radius:2px;margin-right:4px"></span>Aprobată</span>
      <span><span style="display:inline-block;width:12px;height:12px;background:#fef9c3;border-radius:2px;margin-right:4px"></span>În așteptare</span>
      <span><span style="display:inline-block;width:12px;height:12px;background:#fee2e2;border-radius:2px;margin-right:4px"></span>Respinsă</span>
      <span style="margin-left:auto;color:var(--mist)">Data: ${new Date(data).toLocaleDateString('ro-RO', {
        weekday: 'long',
        day: 'numeric',
        month: 'long',
        year: 'numeric'
    })}</span>
    </div>`;
}

function quickRezervare(camId, ora, data) {
    openModalRezervare();
    setTimeout( () => {
        document.getElementById('rezCamera').value = camId;
        document.getElementById('rezData').value = data;
        document.getElementById('rezOraStart').value = ora;
    }
    , 100);
}

function viewRezervare(id) {
    const r = DB.rezervari.find(x => x.id === id);
    if (!r)
        return;
    const cam = DB.camere.find(x => x.id === r.cameraId);
    const user = DB.personal.find(x => x.id === r.userId);
    toast(`📅 ${cam ? cam.cod : ''} · ${r.oraStart}–${r.oraEnd} · ${r.materie} · ${user ? user.prenume + ' ' + user.nume : ''}`);
}

function openModalRezervare() {
    document.getElementById('rezervareEditId').value = '';
    document.getElementById('rezCamera').innerHTML = DB.camere.map(c => `<option value="${c.id}">${c.cod} — ${c.nume}</option>`).join('');
    document.getElementById('rezData').value = new Date().toISOString().split('T')[0];
    document.getElementById('rezOraStart').value = '08:00';
    document.getElementById('rezOraEnd').value = '09:00';
    document.getElementById('rezMaterie').value = '';
    document.querySelectorAll('#echipCheckboxes input').forEach(cb => cb.checked = false);
    openModal('modalRezervare');
}

function saveRezervare() {
    if (window._isSaving)
        return;
    window._isSaving = true;
    setTimeout( () => window._isSaving = false, 1000);
    const camId = parseInt(document.getElementById('rezCamera').value);
    const data = document.getElementById('rezData').value;
    const oraStart = document.getElementById('rezOraStart').value;
    const oraEnd = document.getElementById('rezOraEnd').value;
    const materie = document.getElementById('rezMaterie').value;
    if (!materie) {
        toast('⚠️ Completează materia / scopul!');
        return;
    }

    // Check conflict
    const conflict = DB.rezervari.find(r => r.cameraId === camId && r.data === data && r.oraStart === oraStart && r.status !== 'Respinsă');
    if (conflict) {
        toast('⚠️ Sala este deja rezervată în acel interval!');
        return;
    }

    const cam = DB.camere.find(x => x.id === camId);
    const necesitaAprobare = cam && cam.tip !== 'Sală de clasă';
    const echip = Array.from(document.querySelectorAll('#echipCheckboxes input:checked')).map(cb => cb.value);

    const r = {
        id: Date.now(),
        cameraId: camId,
        userId: currentUser.id,
        data,
        oraStart,
        oraEnd,
        materie,
        elevi: document.getElementById('rezElevi').value,
        echipamente: echip.join(', '),
        status: necesitaAprobare ? 'În așteptare aprobare' : 'Aprobată',
        creatLa: new Date().toLocaleDateString('ro-RO')
    };
    DB.rezervari.push(r);
    sbAutoSave('rezervari', r).then(toastSave);

    if (necesitaAprobare) {
        toast('⏳ Rezervare trimisă spre aprobare director și admin patrimoniu!');
        addNotification('Cerere rezervare sală', `${cam.cod} — ${materie} pe ${data} ora ${oraStart}`, 'rezervare', ['director', 'school_admin']);
    } else {
        toast('✅ Sală rezervată cu succes!');
        addNotification('Rezervare sală confirmată', `${cam ? cam.cod : ''} rezervată pe ${data} ora ${oraStart}`, 'rezervare', ['school_admin']);
    }
    addIstoricEvent('rezervare', `Rezervare sală ${cam ? cam.cod : ''} pe ${data} ${oraStart}–${oraEnd} · ${materie}`, currentUser);
    closeModal('modalRezervare');
    renderCalendarRez();
    renderRezLista();
    updateAprobari();
    updateBadges();
}

function renderRezLista(data) {
    const items = data || DB.rezervari;
    const t = document.getElementById('rezListaTable');
    if (!items.length) {
        t.innerHTML = '<tr><td colspan="8"><div class="empty"><div class="empty-icon">📅</div><p>Nicio rezervare.</p></div></td></tr>';
        return;
    }
    const sb = {
        Aprobată: 'b-green',
        'În așteptare aprobare': 'b-yellow',
        Respinsă: 'b-red'
    };
    t.innerHTML = items.sort( (a, b) => b.data.localeCompare(a.data)).map(r => {
        const cam = DB.camere.find(x => x.id === r.cameraId);
        const user = DB.personal.find(x => x.id === r.userId);
        return `<tr>
      <td>${r.data}</td>
      <td>${r.oraStart}–${r.oraEnd}</td>
      <td>${cam ? cam.cod + ' — ' + cam.nume.substring(0, 20) : '—'}</td>
      <td>${r.materie}</td>
      <td style="font-size:11px">${user ? user.prenume + ' ' + user.nume : '—'}</td>
      <td style="font-size:11px">${r.echipamente || '—'}</td>
      <td><span class="badge ${sb[r.status] || 'b-gray'}">${r.status}</span></td>
      <td>
        ${r.status === 'În așteptare aprobare' && ['director', 'school_admin'].includes(currentUser?.rol) ? `<button class="btn btn-teal btn-sm" onclick="aprobaRezervare(${r.id},true)">✓</button>
           <button class="btn btn-danger btn-sm" onclick="aprobaRezervare(${r.id},false)">✗</button>` : ''}
      </td>
    </tr>`;
    }
    ).join('');
}

function aprobaRezervare(id, approved) {
    const r = DB.rezervari.find(x => x.id === id);
    if (!r)
        return;
    r.status = approved ? 'Aprobată' : 'Respinsă';
    r.aprobatDe = currentUser.prenume + ' ' + currentUser.nume;
    const cam = DB.camere.find(x => x.id === r.cameraId);
    toast(approved ? '✅ Rezervare aprobată!' : '❌ Rezervare respinsă!');
    addNotification(approved ? 'Rezervare aprobată' : 'Rezervare respinsă', `${cam ? cam.cod : ''} pe ${r.data} ora ${r.oraStart}`, 'rezervare', ['profesor', 'school_admin']);
    addIstoricEvent('rezervare', `Rezervare ${approved ? 'aprobată' : 'respinsă'} de ${currentUser.prenume} ${currentUser.nume}: ${cam ? cam.cod : ''} pe ${r.data}`, currentUser);
    renderCalendarRez();
    renderRezLista();
    updateAprobari();
    updateBadges();
}

function switchTabRez(id, el) {
    ['rez-calendar', 'rez-lista', 'rez-aprobari'].forEach(d => {
        const el2 = document.getElementById(d);
        if (el2)
            el2.style.display = 'none';
    }
    );
    document.getElementById(id).style.display = 'block';
    document.querySelectorAll('#section-rezervari .tab').forEach(t => t.classList.remove('active'));
    el.classList.add('active');
    if (id === 'rez-lista')
        renderRezLista();
    if (id === 'rez-aprobari')
        renderRezAprobari();
}

function renderRezAprobari() {
    const pending = DB.rezervari.filter(r => r.status === 'În așteptare aprobare');
    const list = document.getElementById('rezAprobList');
    if (!pending.length) {
        list.innerHTML = '<div class="empty" style="padding:24px"><div class="empty-icon">✅</div><p>Nicio rezervare de aprobat</p></div>';
        return;
    }
    list.innerHTML = pending.map(r => {
        const cam = DB.camere.find(x => x.id === r.cameraId);
        const user = DB.personal.find(x => x.id === r.userId);
        return `<div class="approval-card pending" style="margin:8px 16px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div>
          <div style="font-weight:600;font-size:14px">📅 ${cam ? cam.cod + ' — ' + cam.nume : ''}</div>
          <div style="font-size:12px;color:var(--mist);margin-top:3px">${r.data} · ${r.oraStart}–${r.oraEnd} · ${r.materie}</div>
          <div style="font-size:11px;color:var(--slate);margin-top:3px">Solicitat de: ${user ? user.prenume + ' ' + user.nume : ''} · Echipamente: ${r.echipamente || 'fără'}</div>
        </div>
        <div class="approval-actions">
          <button class="btn btn-teal btn-sm" onclick="aprobaRezervare(${r.id},true)">✓ Aprobă</button>
          <button class="btn btn-danger btn-sm" onclick="aprobaRezervare(${r.id},false)">✗ Respinge</button>
        </div>
      </div>
    </div>`;
    }
    ).join('');
}

// ===== APROBARI GENERALE =====
function updateAprobari() {
    DB.aprobari = DB.aprobari || [];
    const mutPending = DB.mutari.filter(m => m.status === 'În așteptare aprobare').length;
    const rezPending = DB.rezervari.filter(r => r.status === 'În așteptare aprobare').length;
    const achPending = DB.aprobari.filter(a => a.status === 'pending').length;
    const total = mutPending + rezPending + achPending;
    const ab = document.getElementById('aprobariBadge');
    ab.textContent = total;
    ab.style.display = total > 0 ? 'inline' : 'none';
    document.getElementById('rezAprobCount').textContent = rezPending;
    document.getElementById('aprobPendingCount').textContent = total;
    const rezB = document.getElementById('rezervariBadge');
    rezB.textContent = rezPending;
    rezB.style.display = rezPending > 0 ? 'inline' : 'none';
    renderAprobariPending();
}

function renderAprobariPending() {
    const list = document.getElementById('aprobPendingList');
    if (!list)
        return;
    const mutPending = DB.mutari.filter(m => m.status === 'În așteptare aprobare');
    const rezPending = DB.rezervari.filter(r => r.status === 'În așteptare aprobare');
    const achPending = (DB.aprobari || []).filter(a => a.status === 'pending');
    if (!mutPending.length && !rezPending.length && !achPending.length) {
        list.innerHTML = '<div class="empty" style="padding:40px"><div class="empty-icon">✅</div><p>Nicio aprobare în așteptare!</p></div>';
        return;
    }
    let html = '';
    // Achizitii pending
    achPending.forEach(a => {
        const user = DB.personal.find(x => x.id === a.userId);
        const ach = DB.achizitii.find(x => x.id === a.achId);
        const titluDisplay = a.titlu || (ach ? 'Achiziție: ' + (ach.produs || '—') : 'Achiziție');
        html += `<div class="approval-card pending" style="margin:8px 16px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div>
          <div style="font-weight:600">📦 ${titluDisplay}</div>
          <div style="font-size:12px;color:var(--mist)">${a.descriere || ''}</div>
          <div style="font-size:11px;color:var(--slate)">Solicitat de: ${user ? user.prenume + ' ' + user.nume : '—'} · ${a.dataCreare || ''}</div>
        </div>
        <div class="approval-actions">
          <button class="btn btn-teal btn-sm" onclick="aprobaAchizitie(${a.id},true)">✓ Aprobă</button>
          <button class="btn btn-danger btn-sm" onclick="aprobaAchizitie(${a.id},false)">✗ Respinge</button>
        </div>
      </div>
    </div>`;
    }
    );
    mutPending.forEach(m => {
        const b = DB.inventar.find(x => x.id === m.bunId);
        const user = DB.personal.find(x => x.id === m.userId);
        html += `<div class="approval-card pending" style="margin:8px 16px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div>
          <div style="font-weight:600">🔀 Mutare bun — ${b ? b.nrInv : ''}</div>
          <div style="font-size:12px;color:var(--mist)">${b ? b.nume.substring(0, 40) : ''} · ${m.deCamera} → ${m.laCamera}</div>
          <div style="font-size:11px;color:var(--slate)">Motiv: ${m.motiv} · Solicitat de: ${user ? user.prenume + ' ' + user.nume : ''} · ${m.data}</div>
        </div>
        <div class="approval-actions">
          <button class="btn btn-teal btn-sm" onclick="aprobaMutare(${m.id},true)">✓ Aprobă</button>
          <button class="btn btn-danger btn-sm" onclick="aprobaMutare(${m.id},false)">✗ Respinge</button>
        </div>
      </div>
    </div>`;
    }
    );
    rezPending.forEach(r => {
        const cam = DB.camere.find(x => x.id === r.cameraId);
        const user = DB.personal.find(x => x.id === r.userId);
        html += `<div class="approval-card pending" style="margin:8px 16px">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div>
          <div style="font-weight:600">📅 Rezervare sală — ${cam ? cam.cod : ''}</div>
          <div style="font-size:12px;color:var(--mist)">${r.data} · ${r.oraStart}–${r.oraEnd} · ${r.materie}</div>
          <div style="font-size:11px;color:var(--slate)">Solicitat de: ${user ? user.prenume + ' ' + user.nume : ''} · Echipamente: ${r.echipamente || 'fără'}</div>
        </div>
        <div class="approval-actions">
          <button class="btn btn-teal btn-sm" onclick="aprobaRezervare(${r.id},true)">✓ Aprobă</button>
          <button class="btn btn-danger btn-sm" onclick="aprobaRezervare(${r.id},false)">✗ Respinge</button>
        </div>
      </div>
    </div>`;
    }
    );
    list.innerHTML = html;
    // Done list
    const doneList = document.getElementById('aprobDoneList');
    if (!doneList)
        return;
    const mutDone = DB.mutari.filter(m => ['Finalizată', 'Respinsă'].includes(m.status));
    const rezDone = DB.rezervari.filter(r => ['Aprobată', 'Respinsă'].includes(r.status));
    const achDone = (DB.aprobari || []).filter(a => ['aprobat', 'respins'].includes(a.status));
    if (!mutDone.length && !rezDone.length && !achDone.length) {
        doneList.innerHTML = '<div class="empty" style="padding:24px"><p>Nicio aprobare procesată.</p></div>';
        return;
    }
    let doneHtml = '';
    achDone.slice(0, 5).forEach(a => {
        const aprobat = a.status === 'aprobat';
        doneHtml += `<div class="approval-card ${aprobat ? 'approved' : 'rejected'}" style="margin:8px 16px">
      <div style="font-weight:600">📦 ${a.titlu} — <span class="badge ${aprobat ? 'b-green' : 'b-red'}">${aprobat ? 'Aprobat' : 'Respins'}</span></div>
      <div style="font-size:11px;color:var(--mist);margin-top:4px">${a.descriere || ''} ${a.aprobatDe ? '· Procesat de: ' + a.aprobatDe : ''}</div>
    </div>`;
    }
    );
    [...mutDone.slice(0, 5), ...rezDone.slice(0, 5)].forEach(item => {
        const isM = !!item.bunId;
        const statusCls = item.status === 'Finalizată' || item.status === 'Aprobată' ? 'approved' : 'rejected';
        doneHtml += `<div class="approval-card ${statusCls}" style="margin:8px 16px">
      <div style="font-weight:600">${isM ? '🔀 Mutare' : '📅 Rezervare'} — <span class="badge ${item.status === 'Finalizată' || item.status === 'Aprobată' ? 'b-green' : 'b-red'}">${item.status}</span></div>
      <div style="font-size:11px;color:var(--mist);margin-top:4px">${isM ? (item.deCamera + ' → ' + item.laCamera) : (item.data + ' ' + item.oraStart)} ${item.aprobatDe ? '· Procesat de: ' + item.aprobatDe : ''}</div>
    </div>`;
    }
    );
    doneList.innerHTML = doneHtml;
}

function switchTabAprob(id, el) {
    ['aprob-pending', 'aprob-done'].forEach(d => {
        document.getElementById(d).style.display = 'none';
    }
    );
    document.getElementById(id).style.display = 'block';
    document.querySelectorAll('#section-aprobari .tab').forEach(t => t.classList.remove('active'));
    el.classList.add('active');
}

// ===== ISTORIC & LOG =====

function addIstoricEvent(tip, descriere, user) {
    const ev = {
        id: Date.now(),
        tip,
        descriere,
        user: user ? user.prenume + ' ' + user.nume : 'Sistem',
        rol: user ? (ROLE_LABELS[user.rol] || user.rol) : '',
        timestamp: new Date().toLocaleString('ro-RO'),
        data: new Date().toLocaleDateString('ro-RO')
    };
    istoricLog.unshift(ev);
    sbAutoSave('istoric_log', ev);
    persistIstoric();
    // Cache local ca backup (sursa principala: Supabase)
    renderIstoric();
}

function renderIstoric(data) {
    const items = data || istoricLog;
    document.getElementById('istoricCount').textContent = items.length + ' evenimente';
    const list = document.getElementById('istoricList');
    if (!items.length) {
        list.innerHTML = '<div class="empty" style="padding:30px"><div class="empty-icon">📜</div><p>Nicio activitate înregistrată.</p></div>';
        return;
    }
    const tipColors = {
        mutare: '#0d7c6b',
        inventar: '#1a6fa8',
        rezervare: '#7c3aed',
        aprobare: '#0891b2',
        mentenanta: '#d97706',
        import: '#0369a1',
        auth: '#1a1f2e'
    };
    const tipIcons = {
        mutare: '🔀',
        inventar: '📦',
        rezervare: '📅',
        aprobare: '✅',
        mentenanta: '🔧',
        import: '📥',
        auth: '🔐'
    };
    list.innerHTML = items.map(e => `
    <div class="history-item">
      <div class="history-icon" style="background:${tipColors[e.tip] || '#4a5168'}20;color:${tipColors[e.tip] || '#4a5168'}">${tipIcons[e.tip] || '📌'}</div>
      <div class="history-content">
        <div class="history-title">${e.descriere}</div>
        <div class="history-meta">🕐 ${e.timestamp}</div>
      </div>
      <div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px">
        <span class="history-user">👤 ${e.user}</span>
        <span class="badge b-gray" style="font-size:9px">${e.tip}</span>
      </div>
    </div>`).join('');
}

function filterIstoric(q) {
    const s = (q || '').toLowerCase();
    const tip = document.getElementById('filterIstoricTip').value;
    const userId = document.getElementById('filterIstoricUser').value;
    renderIstoric(istoricLog.filter(e => (!s || e.descriere.toLowerCase().includes(s) || e.user.toLowerCase().includes(s)) && (!tip || e.tip === tip) && (!userId || e.user === userId)));
}

function exportAuditLog() {
    const headers = ['Timestamp', 'Tip', 'Descriere', 'Utilizator', 'Rol'];
    const rows = istoricLog.map(e => [e.timestamp, e.tip, e.descriere, e.user, e.rol].map(v => `"${v}"`).join(';'));
    const csv = '\uFEFF' + headers.join(';') + '\n' + rows.join('\n');
    downloadFile(csv, 'audit_log_' + getDateStr() + '.csv', 'text/csv;charset=utf-8');
    toast('✅ Log audit exportat!');
}

function genAudit(tip) {
    const de = document.getElementById('auditDe')?.value || '';
    const pana = document.getElementById('auditPana')?.value || '';

    if (tip === 'sali') {
        let rez = [...(DB.rezervari || [])];
        if (de)
            rez = rez.filter(r => (toISODate(r.data) || r.data || '') >= de);
        if (pana)
            rez = rez.filter(r => (toISODate(r.data) || r.data || '') <= pana);
        rez.sort( (a, b) => (a.data || '').localeCompare(b.data || ''));
        const rows = rez.map(r => {
            const cam = DB.camere.find(x => x.id === r.cameraId);
            const user = DB.personal.find(x => x.id === r.userId);
            return '<tr><td>' + (r.data || '—') + '</td><td>' + (r.oraStart || '') + '–' + (r.oraEnd || '') + '</td><td>' + (cam ? cam.cod + ' — ' + cam.nume : '—') + '</td><td>' + (r.materie || '—') + '</td><td>' + (r.elevi || '—') + '</td><td>' + (r.echipamente || '—') + '</td><td>' + (r.status || '—') + '</td><td>' + (r.aprobatDe || (user ? user.prenume + ' ' + user.nume : '—')) + '</td></tr>';
        }
        ).join('');
        const html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Audit Utilizare Sali</title><style>body{font-family:Arial,sans-serif;font-size:12px;padding:20px} h1{font-size:15px;text-align:center} table{width:100%;border-collapse:collapse} th,td{border:1px solid #ddd;padding:6px;text-align:left} th{background:#f5f5f5}</style></head><body>' + '<div style="text-align:center;margin-bottom:16px;border-bottom:2px solid #333;padding-bottom:12px"><div style="font-size:11px;color:#666">COLEGIUL NATIONAL VASILE GOLDIS ARAD</div>' + '<h1>RAPORT AUDIT — UTILIZARE SALI</h1>' + '<div style="font-size:11px;color:#666">Generat: ' + new Date().toLocaleString('ro-RO') + ' · De: ' + (currentUser?.prenume) + ' ' + (currentUser?.nume) + '</div>' + (de || pana ? '<div style="font-size:11px;color:#666">Perioada: ' + (de || '—') + ' → ' + (pana || '—') + '</div>' : '') + '</div><table><thead><tr><th>Data</th><th>Orar</th><th>Sala</th><th>Materie/Scop</th><th>Elevi</th><th>Echipamente</th><th>Status</th><th>Aprobat de</th></tr></thead><tbody>' + rows + '</tbody></table>' + '<div style="margin-top:30px;text-align:right;font-size:11px;color:#999">Total: ' + rez.length + ' rezervari · PatrimoNet CN Vasile Goldis Arad</div></body></html>';
        const win = window.open('', '_blank');
        win.document.write(html);
        win.document.close();
        setTimeout( () => win.print(), 500);
        toast('Raport audit utilizare sali generat!');
        return;
    }

    let items = istoricLog.filter(e => e.tip === tip || tip === 'user');
    if (tip === 'user') {
        const u = document.getElementById('auditUser')?.value;
        if (u)
            items = istoricLog.filter(e => e.user === u);
    }
    if (de)
        items = items.filter(e => e.data >= de);
    if (pana)
        items = items.filter(e => e.data <= pana);
    const titlu = {
        mutari: 'Audit Mutari Bunuri',
        user: 'Audit Activitate Utilizator',
        inventar: 'Audit Modificari Inventar'
    }[tip] || 'Audit';
    const html2 = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>' + titlu + '</title><style>body{font-family:Arial,sans-serif;font-size:12px;padding:20px} h1{font-size:15px;text-align:center} table{width:100%;border-collapse:collapse} th,td{border:1px solid #ddd;padding:6px;text-align:left} th{background:#f5f5f5} tr:nth-child(even){background:#fafafa}</style></head><body>' + '<div style="text-align:center;margin-bottom:16px;border-bottom:2px solid #333;padding-bottom:12px"><div style="font-size:11px;color:#666">COLEGIUL NATIONAL VASILE GOLDIS ARAD</div>' + '<h1>RAPORT AUDIT — ' + titlu.toUpperCase() + '</h1>' + '<div style="font-size:11px;color:#666">Generat: ' + new Date().toLocaleString('ro-RO') + ' · De: ' + (currentUser?.prenume) + ' ' + (currentUser?.nume) + '</div></div>' + '<table><thead><tr><th>Data/Ora</th><th>Tip</th><th>Descriere</th><th>Utilizator</th><th>Rol</th></tr></thead><tbody>' + items.map(e => '<tr><td>' + e.timestamp + '</td><td>' + e.tip + '</td><td>' + e.descriere + '</td><td>' + e.user + '</td><td>' + e.rol + '</td></tr>').join('') + '</tbody></table><div style="margin-top:30px;text-align:right;font-size:11px;color:#999">Total: ' + items.length + ' evenimente · PatrimoNet CN Vasile Goldis Arad</div></body></html>';
    const win = window.open('', '_blank');
    win.document.write(html2);
    win.document.close();
    setTimeout( () => win.print(), 500);
    toast('Raport audit generat!');
}

