function applyRolePermissions() {
    if (!currentUser)
        return;

    let perm = { ...(ROLE_PERMISSIONS[currentUser.rol] || ROLE_PERMISSIONS.profesor) };

    // PATCH: If SuperAdmin is inside a tenant, grant all school_admin sections
    if (currentUser.rol === 'super_admin' && window.CURRENT_TENANT_CODE) {
        const schoolPerms = ROLE_PERMISSIONS.school_admin;
        perm.sections = [...new Set([...perm.sections, ...schoolPerms.sections])];
    }

    // First SHOW ALL nav items, then hide what's not allowed
    document.querySelectorAll('.nav-item[onclick]').forEach(el => {
        el.style.display = 'flex';
    }
    );
    // Now hide items not in permissions
    document.querySelectorAll('.nav-item[onclick]').forEach(el => {
        const onclickAttr = el.getAttribute('onclick') || '';
        const match = onclickAttr.match(/nav\('([^']+)'/);
        if (match) {
            const section = match[1];
            el.style.display = perm.sections.includes(section) ? 'flex' : 'none';
        }
    }
    );
    // Handle role-gated items specifically
    document.querySelectorAll('.nav-item[data-roles], .nav-group[data-roles]').forEach(el => {
        const roles = el.getAttribute('data-roles').split(',');
        if (!roles.includes(currentUser.rol)) {
            el.style.display = 'none';
        }
    }
    );

    // Hide empty nav groups
    document.querySelectorAll('.nav-group').forEach(group => {
        const items = Array.from(group.querySelectorAll('.nav-item'));
        const hasVisible = items.some(item => item.style.display !== 'none');
        group.style.display = hasVisible ? 'block' : 'none';
    }
    );

    // Hide Import SIIIR global button for strict roles
    const importBtn = document.querySelector('button[onclick="importSIIIRData()"]');
    if (importBtn) {
        importBtn.parentElement.style.display = ['super_admin'].includes(currentUser.rol) ? 'none' : 'block';
    }
}

