// ===== ANAF LOOKUP =====
async function cautaANAF() {
    const cuiRaw = document.getElementById('furnCuiSearch').value.trim().replace(/^RO/i, '');
    if (!cuiRaw || isNaN(cuiRaw)) {
        toast('⚠️ Introdu un CUI valid (doar cifre)');
        return;
    }

    const btn = document.getElementById('btnAnaf');
    const status = document.getElementById('anafStatus');
    btn.disabled = true;
    btn.textContent = '⏳ Caută...';
    status.textContent = 'Se interoghează ANAF...';
    status.style.color = 'var(--mist)';

    try {
        // Try multiple CORS-friendly ANAF proxy services
        let firma = null;
        const errors = [];

        // Option 1: openapi.ro (Romanian public API aggregator)
        try {
            const r1 = await fetch(`https://api.openapi.ro/api/companies/${cuiRaw}`, {
                headers: {
                    'x-api-key': 'public',
                    'Accept': 'application/json'
                }
            });
            if (r1.ok) {
                const d1 = await r1.json();
                if (d1 && d1.denumire) {
                    firma = {
                        denumire: d1.denumire,
                        adresa: d1.adresa || d1.sediu_social || '',
                        judet: d1.judet || d1.localitate || '',
                        scpTVA: d1.tva || d1.platitor_tva || false
                    };
                }
            }
        } catch (e1) {
            errors.push('openapi.ro: ' + e1.message);
        }

        // Option 2: Direct ANAF with no-cors workaround via allorigins proxy
        if (!firma) {
            try {
                const today = new Date().toISOString().split('T')[0];
                const anafUrl = 'https://webservicesp.anaf.ro/api/PlatitorTvaRest/api/v8/ws/tva';
                const proxyUrl = 'https://api.allorigins.win/raw?url=' + encodeURIComponent(anafUrl);
                const r2 = await fetch(proxyUrl, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify([{
                        cui: parseInt(cuiRaw),
                        data: today
                    }])
                });
                if (r2.ok) {
                    const d2 = await r2.json();
                    const f2 = d2?.found?.[0];
                    if (f2?.denumire) {
                        firma = {
                            denumire: f2.denumire,
                            adresa: f2.adresa || '',
                            judet: f2.judet || '',
                            scpTVA: f2.scpTVA || false
                        };
                    }
                }
            } catch (e2) {
                errors.push('allorigins: ' + e2.message);
            }
        }

        if (firma) {
            document.getElementById('furnNume').value = firma.denumire || '';
            document.getElementById('furnCui').value = 'RO' + cuiRaw;
            document.getElementById('furnAdresa').value = firma.adresa || '';
            document.getElementById('furnJudet').value = firma.judet || '';
            document.getElementById('furnTva').value = firma.scpTVA ? '✅ Plătitor TVA' : '❌ Neplătitor TVA';
            status.textContent = '✅ Date preluate: ' + firma.denumire;
            status.style.color = 'var(--teal)';
            toast('✅ Date găsite: ' + firma.denumire);
        } else {
            document.getElementById('furnCui').value = 'RO' + cuiRaw;
            status.innerHTML = '⚠️ Serviciile ANAF nu sunt accesibile din browser. Completează manual sau verifică pe <a href="https://www.anaf.ro/anaf/internet/RO/cautare-date-fiscale" target="_blank" style="color:var(--sky)">anaf.ro</a>.';
            status.style.color = 'var(--gold)';
        }
    } catch (e) {
        document.getElementById('furnCui').value = 'RO' + cuiRaw;
        status.innerHTML = '⚠️ Eroare: ' + e.message + '. Completează manual.';
        status.style.color = 'var(--gold)';
    } finally {
        btn.disabled = false;
        btn.textContent = '🔍 Caută ANAF';
    }
}

