function toggleLocatiiMultiple() {
    const qty = parseInt(document.getElementById('bunQty').value) || 1;
    const section = document.getElementById('locatiiMultipleSection');
    if (qty > 1) {
        section.style.display = 'block';
        if (!document.querySelector('.locatie-row'))
            adaugaLocatie();
        updateLocatiiSumar();
    } else {
        section.style.display = 'none';
    }
}

function adaugaLocatie() {
    const list = document.getElementById('locatiiList');
    const idx = list.querySelectorAll('.locatie-row').length;

    // Build camera options
    const cameraOpts = DB.camere.map(cam => {
        const cld = DB.cladiri.find(x => x.id === cam.cladireId);
        return `<option value="${cam.id}">${cld ? cld.cod + '-' : ''} ${cam.cod} — ${cam.nume || ''}</option>`;
    }
    ).join('');

    const row = document.createElement('div');
    row.className = 'locatie-row';
    row.style.cssText = 'display:flex;gap:8px;align-items:center;margin-bottom:8px';
    row.innerHTML = `
    <select style="flex:2;padding:7px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--ink);font-size:12px" onchange="updateLocatiiSumar()">
      <option value="">— Selectează camera —</option>${cameraOpts}
    </select>
    <input type="number" min="1" value="1" placeholder="Cant." 
      style="width:70px;padding:7px 10px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--ink);font-size:12px;text-align:center"
      onchange="updateLocatiiSumar()">
    <button type="button" onclick="this.parentElement.remove();updateLocatiiSumar()" 
      style="width:28px;height:28px;border-radius:6px;background:var(--surface);border:1px solid var(--border);color:var(--mist);cursor:pointer;flex-shrink:0">✕</button>
  `;
    list.appendChild(row);
    updateLocatiiSumar();
}

function updateLocatiiSumar() {
    const qty = parseInt(document.getElementById('bunQty').value) || 1;
    const list = document.getElementById('locatiiList');
    let total = 0;
    if (list) {
        const rows = Array.from(list.children);
        rows.forEach(row => {
            const qtyInput = row.querySelector('input[type="number"]');
            total += parseInt(qtyInput?.value) || 0;
        }
        );
    }
    const sumar = document.getElementById('locatiiSumar');
    if (sumar) {
        const diff = qty - total;
        if (diff === 0) {
            sumar.innerHTML = `<span style="color:var(--teal)">✅ Distribuire completă: ${total}/${qty} bucăți alocate</span>`;
        } else if (diff > 0) {
            sumar.innerHTML = `<span style="color:var(--gold)">⚠️ Mai sunt ${diff} bucăți nealocate (${total}/${qty})</span>`;
        } else {
            sumar.innerHTML = `<span style="color:var(--rose)">❌ Depășit cu ${Math.abs(diff)} bucăți! (${total}/${qty})</span>`;
        }
    }
}

function getLocatiiFromModal() {
    const list = document.getElementById('locatiiList');
    if (!list)
        return [];

    const locatii = [];
    // Parcurgem toate rândurile copil directe create de adaugaLocatie()
    Array.from(list.children).forEach(row => {
        const selects = row.querySelectorAll('select');
        const qtyInput = row.querySelector('input[type="number"]');

        let cladireId = null;
        let cameraId = null;
        let qty = parseInt(qtyInput?.value) || 1;

        // Structura nouă (versiunea cu 2 select-uri: clădire și cameră)
        if (selects.length === 2) {
            cladireId = parseInt(selects[0].value) || null;
            cameraId = parseInt(selects[1].value) || null;
        }// Structura veche fallback (un singur select pentru cameră)
        else if (selects.length === 1) {
            cameraId = parseInt(selects[0].value) || null;
            // Deducem clădirea din cameră
            if (cameraId && typeof DB !== 'undefined' && DB.camere) {
                const cam = DB.camere.find(c => c.id === cameraId);
                if (cam)
                    cladireId = cam.cladireId;
            }
        }

        if (cameraId) {
            locatii.push({
                cladireId: cladireId,
                cameraId: cameraId,
                cant: qty
            });
        }
    }
    );

    return locatii;
}

function showLocatii(bunId) {
    const b = DB.inventar.find(x => x.id === bunId);
    if (!b || !b.locatii)
        return;
    let html = `<div style="font-weight:700;font-size:15px;margin-bottom:12px">📍 Distribuție locații: ${b.nume}</div>`;
    html += '<table style="width:100%;border-collapse:collapse">';
    html += '<thead><tr><th style="text-align:left;padding:6px;font-size:12px;border-bottom:1px solid var(--border)">Locație</th><th style="text-align:center;padding:6px;font-size:12px;border-bottom:1px solid var(--border)">Cantitate</th></tr></thead><tbody>';
    b.locatii.forEach(loc => {
        const cam = DB.camere.find(x => x.id === loc.cameraId);
        const cld = cam ? DB.cladiri.find(x => x.id === cam.cladireId) : null;
        html += `<tr><td style="padding:8px 6px;font-size:13px;border-bottom:1px solid var(--surface)">${cld ? cld.cod + ' / ' : ''}${cam ? cam.cod + ' — ' + (cam.nume || '') : '—'}</td><td style="text-align:center;padding:8px 6px;font-weight:700;border-bottom:1px solid var(--surface)">${loc.qty} buc</td></tr>`;
    }
    );
    const total = b.locatii.reduce( (s, l) => s + (l.qty || 0), 0);
    html += `<tr style="background:var(--surface)"><td style="padding:8px 6px;font-weight:600">TOTAL</td><td style="text-align:center;padding:8px 6px;font-weight:700;color:var(--teal)">${total} buc</td></tr>`;
    html += '</tbody></table>';

    const m = document.createElement('div');
    m.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:9999;display:flex;align-items:center;justify-content:center';
    m.innerHTML = `<div style="background:var(--white);border-radius:16px;padding:24px;width:420px;max-height:80vh;overflow-y:auto;box-shadow:var(--shadow-lg)">${html}
    <button class="btn btn-outline" style="width:100%;margin-top:16px" onclick="this.closest('[style*=fixed]').remove()">Închide</button>
  </div>`;
    document.body.appendChild(m);
}

// One-time migration: fix tasks with empty titlu in Supabase
async function fixTaskTitluInSupabase() {
    if (!SUPABASE_ENABLED || !sbClient)
        return;
    const tasksToFix = DB.tasks.filter(t => !t.titlu || t.titlu === '—');
    for (const t of tasksToFix) {
        const titlu = t.title || (t.desc ? t.desc.substring(0, 50) : '—');
        t.titlu = titlu;
        if (t._sbId) {
            await sbClient.from('tasks').update({
                titlu
            }).eq('id', t._sbId);
        }
    }
    if (tasksToFix.length)
        renderTasks();
}

